import React, { useState, useEffect } from 'react';
import {
  Grid,
  Card,
  CardContent,
  Typography,
  Box,
  LinearProgress,
  Chip,
  Avatar,
  IconButton,
  Paper,
  Fade,
  Zoom,
  Container,
} from '@mui/material';
import {
  TrendingUp,
  TrendingDown,
  Warning,
  CheckCircle,
  Refresh,
  Person,
  Timer,
  Analytics,
  MonitorHeart,
  Speed,
  Shield,
} from '@mui/icons-material';
import PostureChart from '../components/PostureChart';
import RealTimeMonitor from '../components/RealTimeMonitor';

const Dashboard = () => {
  const [postureData, setPostureData] = useState({
    currentPosture: 'Excellent',
    postureScore: 92,
    dailyAverage: 85,
    weeklyTrend: 8.5,
    sessionsToday: 12,
    totalTime: '8h 32m',
    riskLevel: 'Low',
  });

  const [recentAlerts, setRecentAlerts] = useState([
    { id: 1, type: 'success', message: 'Perfect posture maintained for 2 hours!', time: '5 min ago' },
    { id: 2, type: 'info', message: 'Posture calibration completed successfully', time: '1 hour ago' },
    { id: 3, type: 'warning', message: 'Take a movement break - 45 minutes sitting', time: '2 hours ago' },
  ]);

  const StatCard = ({ title, value, subtitle, icon, color, trend, delay = 0 }) => (
    <Zoom in={true} style={{ transitionDelay: `${delay}ms` }}>
      <Card 
        sx={{ 
          height: '100%',
          minHeight: 180,
          position: 'relative',
          overflow: 'visible',
          display: 'flex',
          flexDirection: 'column',
          '&::before': {
            content: '""',
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            height: 4,
            background: `linear-gradient(90deg, ${
              color === 'primary' ? '#8B5CF6, #EC4899' :
              color === 'success' ? '#10B981, #059669' :
              color === 'info' ? '#06B6D4, #0891B2' :
              '#F59E0B, #D97706'
            })`,
            borderRadius: '20px 20px 0 0',
          },
        }}
      >
        <CardContent sx={{ 
          flexGrow: 1, 
          display: 'flex', 
          flexDirection: 'column',
          justifyContent: 'space-between',
          p: 3,
        }}>
          <Box sx={{ display: 'flex', alignItems: 'flex-start', mb: 2 }}>
            <Avatar 
              sx={{ 
                background: `linear-gradient(135deg, ${
                  color === 'primary' ? '#8B5CF6, #EC4899' :
                  color === 'success' ? '#10B981, #059669' :
                  color === 'info' ? '#06B6D4, #0891B2' :
                  '#F59E0B, #D97706'
                })`,
                width: 48,
                height: 48,
                mr: 2,
                boxShadow: `0 8px 24px rgba(${
                  color === 'primary' ? '139, 92, 246' :
                  color === 'success' ? '16, 185, 129' :
                  color === 'info' ? '6, 182, 212' :
                  '245, 158, 11'
                }, 0.3)`,
              }}
            >
              {icon}
            </Avatar>
            <Box sx={{ flexGrow: 1, minWidth: 0 }}>
              <Typography 
                variant="caption" 
                sx={{ 
                  color: 'text.secondary', 
                  fontWeight: 600,
                  textTransform: 'uppercase',
                  letterSpacing: 1,
                  fontSize: '0.7rem',
                  display: 'block',
                  mb: 0.5,
                }}
              >
                {title}
              </Typography>
              <Typography 
                variant="h4" 
                sx={{ 
                  fontWeight: 800,
                  background: `linear-gradient(135deg, ${
                    color === 'primary' ? '#8B5CF6, #EC4899' :
                    color === 'success' ? '#10B981, #059669' :
                    color === 'info' ? '#06B6D4, #0891B2' :
                    '#F59E0B, #D97706'
                  })`,
                  WebkitBackgroundClip: 'text',
                  WebkitTextFillColor: 'transparent',
                  backgroundClip: 'text',
                  fontSize: { xs: '1.75rem', sm: '2rem', md: '2.125rem' },
                  lineHeight: 1.1,
                  wordBreak: 'break-word',
                }}
              >
                {value}
              </Typography>
            </Box>
          </Box>
          
          <Box sx={{ mt: 'auto' }}>
            {subtitle && (
              <Typography 
                variant="body2" 
                sx={{ 
                  color: 'text.secondary',
                  mb: trend ? 1.5 : 0,
                  fontWeight: 500,
                  fontSize: '0.8rem',
                }}
              >
                {subtitle}
              </Typography>
            )}
            
            {trend && (
              <Box
                sx={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  px: 1.5,
                  py: 0.5,
                  borderRadius: 2,
                  background: trend > 0 
                    ? 'linear-gradient(135deg, rgba(16, 185, 129, 0.1), rgba(5, 150, 105, 0.1))'
                    : 'linear-gradient(135deg, rgba(239, 68, 68, 0.1), rgba(220, 38, 38, 0.1))',
                  border: trend > 0
                    ? '1px solid rgba(16, 185, 129, 0.2)'
                    : '1px solid rgba(239, 68, 68, 0.2)',
                }}
              >
                {trend > 0 ? (
                  <TrendingUp sx={{ color: '#10B981', mr: 0.5, fontSize: 16 }} />
                ) : (
                  <TrendingDown sx={{ color: '#EF4444', mr: 0.5, fontSize: 16 }} />
                )}
                <Typography 
                  variant="caption" 
                  sx={{ 
                    color: trend > 0 ? '#10B981' : '#EF4444',
                    fontWeight: 700,
                    fontSize: '0.75rem',
                  }}
                >
                  {Math.abs(trend)}% vs last week
                </Typography>
              </Box>
            )}
          </Box>
        </CardContent>
      </Card>
    </Zoom>
  );

  const AlertItem = ({ alert, index }) => (
    <Fade in={true} style={{ transitionDelay: `${index * 100}ms` }}>
      <Box 
        sx={{ 
          display: 'flex', 
          alignItems: 'flex-start', 
          p: 2, 
          mb: 1.5,
          borderRadius: 3,
          background: (theme) => 
            theme.palette.mode === 'dark'
              ? 'linear-gradient(135deg, rgba(26, 27, 58, 0.4) 0%, rgba(22, 23, 50, 0.4) 100%)'
              : 'linear-gradient(135deg, rgba(255, 255, 255, 0.6) 0%, rgba(248, 250, 252, 0.6) 100%)',
          backdropFilter: 'blur(10px)',
          border: (theme) => 
            theme.palette.mode === 'dark'
              ? `1px solid rgba(${
                  alert.type === 'warning' ? '245, 158, 11' : 
                  alert.type === 'success' ? '16, 185, 129' : '6, 182, 212'
                }, 0.2)`
              : `1px solid rgba(${
                  alert.type === 'warning' ? '217, 119, 6' : 
                  alert.type === 'success' ? '5, 150, 105' : '14, 165, 233'
                }, 0.15)`,
          transition: 'all 0.3s ease',
          '&:hover': {
            transform: 'translateX(4px)',
            boxShadow: (theme) => 
              theme.palette.mode === 'dark'
                ? `0 4px 20px rgba(${
                    alert.type === 'warning' ? '245, 158, 11' : 
                    alert.type === 'success' ? '16, 185, 129' : '6, 182, 212'
                  }, 0.15)`
                : `0 4px 20px rgba(${
                    alert.type === 'warning' ? '217, 119, 6' : 
                    alert.type === 'success' ? '5, 150, 105' : '14, 165, 233'
                  }, 0.1)`,
          },
        }}
      >
        <Avatar 
          sx={{ 
            background: `linear-gradient(135deg, ${
              alert.type === 'warning' ? '#F59E0B, #D97706' : 
              alert.type === 'success' ? '#10B981, #059669' : '#06B6D4, #0891B2'
            })`,
            mr: 2,
            width: 32,
            height: 32,
            boxShadow: `0 4px 16px rgba(${
              alert.type === 'warning' ? '245, 158, 11' : 
              alert.type === 'success' ? '16, 185, 129' : '6, 182, 212'
            }, 0.2)`,
          }}
        >
          {alert.type === 'warning' ? <Warning sx={{ fontSize: 18 }} /> : 
           alert.type === 'success' ? <CheckCircle sx={{ fontSize: 18 }} /> : <Analytics sx={{ fontSize: 18 }} />}
        </Avatar>
        <Box sx={{ flexGrow: 1, minWidth: 0 }}>
          <Typography 
            variant="body2" 
            sx={{ 
              fontWeight: 600, 
              mb: 0.5,
              fontSize: '0.85rem',
              lineHeight: 1.4,
            }}
          >
            {alert.message}
          </Typography>
          <Typography 
            variant="caption" 
            sx={{ 
              color: 'text.secondary', 
              fontWeight: 500,
              fontSize: '0.7rem',
            }}
          >
            {alert.time}
          </Typography>
        </Box>
      </Box>
    </Fade>
  );

  return (
    <Container maxWidth="xl" sx={{ px: { xs: 2, sm: 3 } }}>
      {/* Header Section */}
      <Box sx={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: { xs: 'flex-start', sm: 'center' },
        flexDirection: { xs: 'column', sm: 'row' },
        mb: { xs: 3, sm: 4 },
        gap: { xs: 2, sm: 0 },
      }}>
        <Box>
          <Typography 
            variant="h1" 
            sx={{ 
              fontWeight: 800,
              fontSize: { xs: '2.5rem', sm: '3rem', md: '3.5rem' },
              lineHeight: 1.1,
              mb: 1,
            }}
          >
            Dashboard
          </Typography>
          <Typography 
            variant="subtitle1" 
            sx={{ 
              color: 'text.secondary',
              fontWeight: 500,
              opacity: 0.8,
              fontSize: { xs: '0.9rem', sm: '1rem' },
            }}
          >
            Real-time posture monitoring & analytics
          </Typography>
        </Box>
        <IconButton 
          sx={{
            background: 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)',
            color: '#FFFFFF',
            width: { xs: 48, sm: 56 },
            height: { xs: 48, sm: 56 },
            boxShadow: '0 8px 32px rgba(139, 92, 246, 0.3)',
            '&:hover': {
              transform: 'scale(1.05) rotate(180deg)',
              boxShadow: '0 12px 40px rgba(139, 92, 246, 0.4)',
            },
            transition: 'all 0.3s ease',
          }}
        >
          <Refresh />
        </IconButton>
      </Box>

      {/* Stats Cards Grid */}
      <Grid container spacing={{ xs: 2, sm: 3, md: 4 }} sx={{ mb: { xs: 3, sm: 4 } }}>
        <Grid item xs={12} sm={6} lg={3}>
          <StatCard
            title="Current Status"
            value={postureData.currentPosture}
            icon={<MonitorHeart />}
            color="primary"
            delay={0}
          />
        </Grid>
        
        <Grid item xs={12} sm={6} lg={3}>
          <StatCard
            title="Posture Score"
            value={`${postureData.postureScore}%`}
            subtitle={`Daily average: ${postureData.dailyAverage}%`}
            icon={<Speed />}
            color="success"
            trend={postureData.weeklyTrend}
            delay={100}
          />
        </Grid>
        
        <Grid item xs={12} sm={6} lg={3}>
          <StatCard
            title="Active Time"
            value={postureData.totalTime}
            subtitle={`${postureData.sessionsToday} sessions today`}
            icon={<Timer />}
            color="info"
            delay={200}
          />
        </Grid>
        
        <Grid item xs={12} sm={6} lg={3}>
          <StatCard
            title="Risk Level"
            value={postureData.riskLevel}
            icon={<Shield />}
            color={postureData.riskLevel === 'Low' ? 'success' : 'warning'}
            delay={300}
          />
        </Grid>
      </Grid>

      {/* Main Content Grid */}
      <Grid container spacing={{ xs: 2, sm: 3, md: 4 }}>
        {/* Real-time Monitor */}
        <Grid item xs={12} lg={8}>
          <Fade in={true} style={{ transitionDelay: '400ms' }}>
            <Card 
              sx={{ 
                height: { xs: 'auto', md: 500 },
                minHeight: { xs: 400, md: 500 },
                '&::before': {
                  content: '""',
                  position: 'absolute',
                  top: 0,
                  left: 0,
                  right: 0,
                  height: 4,
                  background: 'linear-gradient(90deg, #8B5CF6, #EC4899)',
                  borderRadius: '20px 20px 0 0',
                },
              }}
            >
              <CardContent sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
                <Typography 
                  variant="h5" 
                  sx={{ 
                    fontWeight: 700,
                    mb: 3,
                    background: (theme) => 
                      theme.palette.mode === 'dark'
                        ? 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)'
                        : 'linear-gradient(135deg, #7C3AED 0%, #DB2777 100%)',
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent',
                    backgroundClip: 'text',
                  }}
                >
                  Real-time Posture Monitoring
                </Typography>
                <Box sx={{ flexGrow: 1 }}>
                  <RealTimeMonitor />
                </Box>
              </CardContent>
            </Card>
          </Fade>
        </Grid>

        {/* Recent Alerts */}
        <Grid item xs={12} lg={4}>
          <Fade in={true} style={{ transitionDelay: '500ms' }}>
            <Card 
              sx={{ 
                height: { xs: 'auto', md: 500 },
                minHeight: { xs: 300, md: 500 },
                display: 'flex',
                flexDirection: 'column',
                '&::before': {
                  content: '""',
                  position: 'absolute',
                  top: 0,
                  left: 0,
                  right: 0,
                  height: 4,
                  background: 'linear-gradient(90deg, #EC4899, #8B5CF6)',
                  borderRadius: '20px 20px 0 0',
                },
              }}
            >
              <Box sx={{ p: 3, borderBottom: '1px solid', borderColor: 'divider' }}>
                <Typography 
                  variant="h5" 
                  sx={{ 
                    fontWeight: 700,
                    background: (theme) => 
                      theme.palette.mode === 'dark'
                        ? 'linear-gradient(135deg, #EC4899 0%, #8B5CF6 100%)'
                        : 'linear-gradient(135deg, #DB2777 0%, #7C3AED 100%)',
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent',
                    backgroundClip: 'text',
                  }}
                >
                  Recent Activity
                </Typography>
              </Box>
              <Box sx={{ 
                flexGrow: 1, 
                overflow: 'auto', 
                p: 2,
                '&::-webkit-scrollbar': {
                  width: 6,
                },
                '&::-webkit-scrollbar-track': {
                  background: 'transparent',
                },
                '&::-webkit-scrollbar-thumb': {
                  background: 'linear-gradient(135deg, #8B5CF6, #EC4899)',
                  borderRadius: 3,
                },
              }}>
                {recentAlerts.map((alert, index) => (
                  <AlertItem key={alert.id} alert={alert} index={index} />
                ))}
              </Box>
            </Card>
          </Fade>
        </Grid>

        {/* Posture Trends Chart */}
        <Grid item xs={12}>
          <Fade in={true} style={{ transitionDelay: '600ms' }}>
            <Card
              sx={{
                '&::before': {
                  content: '""',
                  position: 'absolute',
                  top: 0,
                  left: 0,
                  right: 0,
                  height: 4,
                  background: 'linear-gradient(90deg, #8B5CF6, #EC4899, #06B6D4)',
                  borderRadius: '20px 20px 0 0',
                },
              }}
            >
              <CardContent>
                <Typography 
                  variant="h5" 
                  sx={{ 
                    fontWeight: 700,
                    mb: 3,
                    background: (theme) => 
                      theme.palette.mode === 'dark'
                        ? 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 50%, #06B6D4 100%)'
                        : 'linear-gradient(135deg, #7C3AED 0%, #DB2777 50%, #0891B2 100%)',
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent',
                    backgroundClip: 'text',
                  }}
                >
                  Weekly Posture Analytics
                </Typography>
                <PostureChart />
              </CardContent>
            </Card>
          </Fade>
        </Grid>
      </Grid>
    </Container>
  );
};

export default Dashboard;
